mapper.select:
SELECT id, "timestamp", event_type,
       src_ip::text  AS src_ip,  src_port,
       dest_ip::text AS dest_ip, dest_port,
       proto, payload_json::text AS payload_json
FROM ${t}

     AND "timestamp" >= #{from} 
       AND "timestamp" <  #{to} 
     AND event_type = #{etype} 
     AND (src_ip::text = #{ip} OR dest_ip::text = #{ip}) 
     AND (src_ip::text ILIKE ('%' || #{q} || '%')
                               OR dest_ip::text ILIKE ('%' || #{q} || '%')
                               OR payload_json::text ILIKE ('%' || #{q} || '%')) 

ORDER BY "timestamp" DESC
LIMIT #{limit} OFFSET #{offset}

SELECT count(*) FROM ${t}

     AND "timestamp" >= #{from} 
       AND "timestamp" <  #{to} 
     AND event_type = #{etype} 
     AND (src_ip::text = #{ip} OR dest_ip::text = #{ip}) 
     AND (src_ip::text ILIKE ('%' || #{q} || '%')
                               OR dest_ip::text ILIKE ('%' || #{q} || '%')
                               OR payload_json::text ILIKE ('%' || #{q} || '%'))

SELECT date_trunc('${iv}', "timestamp") AS bucket, event_type, count(*) AS cnt
FROM ${t}

     AND "timestamp" >= #{from} 
       AND "timestamp" <  #{to} 
     AND event_type = #{etype} 

GROUP BY bucket, event_type
ORDER BY bucket

SELECT (payload_json::jsonb)->'alert'->>'signature' AS k, count(*) AS cnt
FROM ${t}
WHERE event_type = 'alert' AND (payload_json::jsonb)->'alert'->>'signature' IS NOT NULL
GROUP BY k ORDER BY cnt DESC LIMIT #{limit}
